mapper.select:
SELECT B1.* FROM ( SELECT businessAreaCd , businessTypeCd , objectNo , objectId , revNo , objectNm , objectType , objectClassCd2 , objectClassNm2 , insertUid , ( SELECT USER_NM FROM DOCS_USER tmp WHERE tmp.USER_ID = insertUid ) AS insertUserNm , ( SELECT USER_NM FROM DOCS_USER tmp WHERE tmp.USER_ID = updateUid ) AS updateUserNm , TO_CHAR(insertDt, 'YYYY-MM-DD') AS insertDt , updateUid , TO_CHAR(updateDt, 'YYYY-MM-DD') AS updateDt , totalPageCnt , productNm , productNo , callId , applyHogiNo , securityTypeCd , securityTypeNm , ROW_NUMBER() OVER (ORDER BY insertDt DESC, objectNo DESC) AS PAGEINDEX FROM (
SELECT info.BUSINESS_AREA_CD AS businessAreaCd , info.BUSINESS_TYPE_CD AS businessTypeCd , info.DOCUMENT_NO AS objectNo , info.OBJECT_ID AS objectId , info.REV_NO AS revNo , info.DOCUMENT_NM AS objectNm , 'DOC' AS objectType , DOC_CLASS_CD2 AS objectClassCd2 , FN_GET_CD_NM('objectClassCd2', DOC_CLASS_CD2, #{sessionLang}) AS objectClassNm2 , INSERT_UID AS insertUid , INSERT_DT AS insertDt , UPDATE_UID AS updateUid , UPDATE_DT AS updateDt , info.TOTAL_PAGE_CNT AS totalPageCnt , ( SELECT ORG_FILE_NM FROM DOCS_PRODUCT_DOCUMENT_FILE tmp WHERE tmp.OBJECT_ID = info.OBJECT_ID AND tmp.FILE_NO = 1 ) AS fileNm , ( SELECT FILE_PATH_NM FROM DOCS_PRODUCT_DOCUMENT_FILE tmp WHERE tmp.OBJECT_ID = info.OBJECT_ID AND tmp.FILE_NO = 1 ) AS filePath , COALESCE(info.APPLY_PRODUCT_NO, '') AS productNm , info.APPLY_PRODUCT_NO AS productNo , CALL_ID AS callId , info.APPLY_HOGI_NO AS applyHogiNo , info.SECURITY_TYPE_CD AS securityTypeCd , FN_GET_CD_NM('securityTypeCd', info.SECURITY_TYPE_CD, #{sessionLang}) AS securityTypeNm
FROM ( SELECT info.* , fileInfo.fileNo AS fileNo , DENSE_RANK() OVER (PARTITION BY DOCUMENT_NO ORDER BY REV_NO DESC) as rnk FROM DOCS_PRODUCT_DOCUMENT info
FROM ( SELECT info.* , fileInfo.fileNo AS fileNo FROM DOCS_PRODUCT_DOCUMENT info
INNER JOIN ( SELECT OBJECT_ID , MAX(FILE_NO) AS fileNo FROM DOCS_PRODUCT_DOCUMENT_FILE GROUP BY OBJECT_ID ) fileInfo ON info.OBJECT_ID = fileInfo.OBJECT_ID WHERE 1=1
AND DOCUMENT_NO LIKE '%' || UPPER(TRIM(#{objectNo})) || '%'
AND DOCUMENT_NM LIKE '%' || #{objectNm} || '%'
AND BUSINESS_AREA_CD = #{businessAreaCd}
AND INSERT_UID = #{insertUid}
AND INSERT_DEPT_NM like #{insertDeptNm}
AND DOC_CLASS_CD2 like #{objectClassCd2}
AND info.APPLY_PRODUCT_NO = #{productCd}
AND info.INSERT_DT BETWEEN TO_DATE(#{insertStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{insertEndDt}, 'YYYY-MM-DD')+1
AND(
(DOCUMENT_NO LIKE '%' || UPPER(TRIM(#{productionInfo.objectNo})) || '%')
)
AND(
(DOCUMENT_NO = UPPER(TRIM(#{productionInfo.objectNo})) )
)
SELECT info.BUSINESS_AREA_CD AS businessAreaCd , info.BUSINESS_TYPE_CD AS businessTypeCd , info.SW_NO AS objectNo , info.OBJECT_ID AS objectId , info.REV_NO AS revNo , info.SW_NM AS objectNm , 'SW' AS objectType , SW_CLASS_CD2 AS objectClassCd2 , FN_GET_CD_NM('objectClassCd2', SW_CLASS_NM2, #{sessionLang}) AS objectClassNm2 , INSERT_UID AS insertUid , INSERT_DT AS insertDt , UPDATE_UID AS updateUid , UPDATE_DT AS updateDt , info.fileNo AS totalPageCnt , ( SELECT ORG_FILE_NM FROM DOCS_PRODUCT_DOCUMENT_FILE tmp WHERE tmp.OBJECT_ID = info.OBJECT_ID AND tmp.FILE_NO = 1 ) AS fileNm , ( SELECT FILE_PATH_NM FROM DOCS_PRODUCT_DOCUMENT_FILE tmp WHERE tmp.OBJECT_ID = info.OBJECT_ID AND tmp.FILE_NO = 1 ) AS filePathNm , COALESCE(info.PRODUCT_NO, '') AS productNm , info.PRODUCT_NO AS productNo , TO_NCHAR('') AS callId , TO_NCHAR('') AS applyHogiNo , info.SECURITY_TYPE_CD AS securityTypeCd , FN_GET_CD_NM('securityTypeCd', info.SECURITY_TYPE_CD, #{sessionLang}) AS securityTypeNm
FROM ( SELECT info.* , fileInfo.fileNo AS fileNo , DENSE_RANK() OVER (PARTITION BY SW_NO ORDER BY REV_NO DESC) as rnk FROM DOCS_PRODUCT_SW info
FROM ( SELECT info.* , fileInfo.fileNo AS fileNo FROM DOCS_PRODUCT_SW info
INNER JOIN ( SELECT OBJECT_ID , MAX(FILE_NO) AS fileNo FROM DOCS_PRODUCT_SW_FILE GROUP BY OBJECT_ID ) fileInfo ON info.OBJECT_ID = fileInfo.OBJECT_ID WHERE 1=1
AND SW_NO LIKE '%' || UPPER(TRIM(#{objectNo})) || '%'
AND SW_NM LIKE '%' || #{objectNm} || '%'
AND BUSINESS_AREA_CD = #{businessAreaCd}
AND INSERT_UID = #{insertUid}
AND INSERT_DEPT_NM = #{insertDeptNm}
AND SW_CLASS_CD2 = #{objectClassCd2}
AND info.PRODUCT_NO = #{productCd}
AND info.INSERT_DT BETWEEN TO_DATE(#{insertStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{insertEndDt}, 'YYYY-MM-DD')+1
AND(
(SW_NO LIKE '%' || UPPER(TRIM(#{productionInfo.objectNo})) || '%')
)
AND(
(SW_NO = UPPER(TRIM(#{productionInfo.objectNo})) )
)
) info
WHERE rnk = 1
ORDER BY insertDt desc, objectNo desc
ORDER BY ${sortColumn} ${order}, objectNo ${order}
) A1 WHERE 1=1
AND PAGEINDEX <= #{end}
) B1
WHERE PAGEINDEX >= #{start}

SELECT COUNT(*) AS TOTAL_COUNT FROM ( SELECT A1.* , ROW_NUMBER() OVER () AS PAGEINDEX , ( SELECT USER_NM FROM DOCS_USER tmp WHERE tmp.USER_ID = insertUid ) AS insertUserNm , ( SELECT USER_NM FROM DOCS_USER tmp WHERE tmp.USER_ID = updateUid ) AS updateUserNm FROM (
SELECT info.BUSINESS_AREA_CD AS businessAreaCd , info.BUSINESS_TYPE_CD AS businessTypeCd , info.DOCUMENT_NO AS objectNo , info.REV_NO AS revNo , info.DOCUMENT_NM AS objectNm , 'DOC' AS objectType , DOC_CLASS_CD2 AS objectClassCd2 , DOC_CLASS_NM2 AS objectClassNm2 , INSERT_UID AS insertUid , TO_CHAR(INSERT_DT, 'YYYY-MM-DD') AS insertDt , UPDATE_UID AS updateUid , TO_CHAR(UPDATE_DT, 'YYYY-MM-DD') AS updateDt , info.fileNo AS totalPageCnt , ( SELECT ORG_FILE_NM FROM DOCS_PRODUCT_DOCUMENT_FILE tmp WHERE tmp.OBJECT_ID = info.OBJECT_ID AND tmp.FILE_NO = 1 ) AS fileNm , ( SELECT FILE_PATH_NM FROM DOCS_PRODUCT_DOCUMENT_FILE tmp WHERE tmp.OBJECT_ID = info.OBJECT_ID AND tmp.FILE_NO = 1 ) AS filePathNm , COALESCE(info.APPLY_PRODUCT_NO, '') AS productNm , info.APPLY_PRODUCT_NO AS applyProductNo , CALL_ID AS callId , info.APPLY_HOGI_NO AS applyHogiNo , info.SECURITY_TYPE_CD AS securityTypeCd
FROM ( SELECT info.* , fileInfo.fileNo AS fileNo , DENSE_RANK() OVER (PARTITION BY DOCUMENT_NO ORDER BY REV_NO DESC) as rnk FROM DOCS_PRODUCT_DOCUMENT info
FROM ( SELECT info.* , fileInfo.fileNo AS fileNo FROM DOCS_PRODUCT_DOCUMENT info
INNER JOIN ( SELECT OBJECT_ID , MAX(FILE_NO) AS fileNo FROM DOCS_PRODUCT_DOCUMENT_FILE GROUP BY OBJECT_ID ) fileInfo ON info.OBJECT_ID = fileInfo.OBJECT_ID WHERE 1=1
AND DOCUMENT_NO LIKE '%' || UPPER(TRIM(#{objectNo})) || '%'
AND DOCUMENT_NM LIKE '%' || #{objectNm} || '%'
AND BUSINESS_AREA_CD = #{businessAreaCd}
AND INSERT_UID = #{insertUid}
AND INSERT_DEPT_NM like #{insertDeptNm}
AND DOC_CLASS_CD2 like #{objectClassCd2}
AND info.APPLY_PRODUCT_NO = #{productCd}
AND info.INSERT_DT BETWEEN TO_DATE(#{insertStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{insertEndDt}, 'YYYY-MM-DD')+1
AND(
(DOCUMENT_NO LIKE '%' || UPPER(TRIM(#{productionInfo.objectNo})) || '%')
)
AND(
(DOCUMENT_NO = UPPER(TRIM(#{productionInfo.objectNo})) )
)
SELECT info.BUSINESS_AREA_CD AS businessAreaCd , info.BUSINESS_TYPE_CD AS businessTypeCd , info.SW_NO AS objectNo , info.REV_NO AS revNo , info.SW_NM AS objectNm , 'SW' AS objectType , SW_CLASS_CD2 AS objectClassCd2 , SW_CLASS_NM2 AS objectClassNm2 , INSERT_UID AS insertUid , TO_CHAR(INSERT_DT, 'YYYY-MM-DD') AS insertDt , UPDATE_UID AS updateUid , TO_CHAR(UPDATE_DT, 'YYYY-MM-DD') AS updateDt , info.fileNo AS totalPageCnt , ( SELECT ORG_FILE_NM FROM DOCS_PRODUCT_DOCUMENT_FILE tmp WHERE tmp.OBJECT_ID = info.OBJECT_ID AND tmp.FILE_NO = 1 ) AS fileNm , ( SELECT FILE_PATH_NM FROM DOCS_PRODUCT_DOCUMENT_FILE tmp WHERE tmp.OBJECT_ID = info.OBJECT_ID AND tmp.FILE_NO = 1 ) AS filePathNm , COALESCE(info.PRODUCT_NO, '') AS productNm , info.PRODUCT_NO AS productNo , TO_NCHAR('') AS callId , TO_NCHAR('') AS applyHogiNo , info.SECURITY_TYPE_CD AS securityTypeCd
FROM ( SELECT info.* , fileInfo.fileNo AS fileNo , DENSE_RANK() OVER (PARTITION BY SW_NO ORDER BY REV_NO DESC) as rnk FROM DOCS_PRODUCT_SW info
FROM ( SELECT info.* , fileInfo.fileNo AS fileNo FROM DOCS_PRODUCT_SW info
INNER JOIN ( SELECT OBJECT_ID , MAX(FILE_NO) AS fileNo FROM DOCS_PRODUCT_SW_FILE GROUP BY OBJECT_ID ) fileInfo ON info.OBJECT_ID = fileInfo.OBJECT_ID WHERE 1=1
AND SW_NO LIKE '%' || UPPER(TRIM(#{objectNo})) || '%'
AND SW_NM LIKE '%' || #{objectNm} || '%'
AND BUSINESS_AREA_CD = #{businessAreaCd}
AND INSERT_UID = #{insertUid}
AND INSERT_DEPT_NM like #{insertDeptNm}
AND SW_CLASS_CD2 like #{objectClassCd2}
AND info.PRODUCT_NO = #{productCd}
AND info.INSERT_DT BETWEEN TO_DATE(#{insertStartDt}, 'YYYY-MM-DD') AND TO_DATE(#{insertEndDt}, 'YYYY-MM-DD')+1
AND(
(SW_NO LIKE '%' || UPPER(TRIM(#{productionInfo.objectNo})) || '%')
)
AND(
(SW_NO = UPPER(TRIM(#{productionInfo.objectNo})) )
)
) info
WHERE rnk = 1
) A1 WHERE 1=1 ) B1

mapper.insert:

	SELECT TO_CHAR(CURRENT_DATE,'YYYYMMDD')||'-'||#{objectTypeCode}||LPAD(COALESCE(SUBSTRING(MAX(REQUEST_NO),11)::integer,0)+1,4,'0') AS REQUEST_NO
	FROM DOCS_REQUEST
	WHERE SUBSTRING(REQUEST_NO,1,10) = TO_CHAR(CURRENT_DATE,'YYYYMMDD')||'-'||#{objectTypeCode}

INSERT INTO DOCS_REQUEST
(
REQUEST_NO
, REQUEST_TYPE
, REQUEST_PURPOSE
, APPROVAL_LINE_ID
, CURRENT_PROCESS_SEQ_NO
, DEPLOY_COMPANY_CD
, USE_START_YMD
, USE_END_YMD
, WATERMARK_YN
, INSERT_USER_CD
, INSERT_DT
, UPDATE_USER_CD
, UPDATE_DT
, STATUS_CD
, OBJECT_TYPE
, BUSINESS_AREA_CD
, WATERMARK_DEPLOY_DT_YN
)
VALUES
(
#{requestNo}
, #{requestType}
, #{requestPurpose}
, #{approvalLineId}
, '2'
, #{sessionUser.companyCd}
, #{deployDate}
, #{validDate}
, #{watermarkYn}
, #{sessionUser.userCd}
, CURRENT_TIMESTAMP
, #{sessionUser.userCd}
, CURRENT_TIMESTAMP
, 'REQUEST'
, #{objectType}
, COALESCE(#{businessAreaCd},#{sessionUser.businessAreaCd})
, #{watermarkDeployDtYn}
)

